mapper.select:
SELECT id as id, dealerId as dealerId, (select dealerName from dealer where id = dealerId) as dealerName, activityType as activityType, activityComment as activityComment FROM activity_config
1=1
AND id = #{id}
AND dealerId
AND activityType = #{activityType}
ORDER BY id DESC

mapper.insert:
