(dealerId,
activityType,
activityComment
)
VALUES(
#{dealerId},
#{activityType},
#{activityComment}
)

mapper.update:
  UPDATE activity_config
  SET dealerId=#{dealerId},
  activityType=#{activityType},
  activityComment=#{activityComment}
WHERE id=#{id}
